CREATE TABLE user_account (
    id BIGSERIAL PRIMARY KEY,
    email VARCHAR(256) NOT NULL UNIQUE,
    password_hash VARCHAR(255) NOT NULL,
    password_login_enabled BOOLEAN NOT NULL DEFAULT TRUE,
    enabled BOOLEAN NOT NULL DEFAULT TRUE,
    last_login_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP
);

ALTER TABLE chat_session ADD COLUMN user_id BIGINT;
ALTER TABLE chat_session ADD COLUMN title VARCHAR(128);
ALTER TABLE chat_session ADD COLUMN selected_chat_model VARCHAR(64);
ALTER TABLE chat_session ADD COLUMN status VARCHAR(16) NOT NULL DEFAULT 'ACTIVE';
ALTER TABLE chat_session ADD COLUMN last_message_at TIMESTAMPTZ;
CREATE UNIQUE INDEX uk_chat_session_user_session ON chat_session(user_id, session_code);

ALTER TABLE chat_turn ADD COLUMN user_id BIGINT;
ALTER TABLE chat_turn ADD COLUMN message_code VARCHAR(64);
ALTER TABLE chat_turn ADD COLUMN client_message_id VARCHAR(64);
ALTER TABLE chat_turn ADD COLUMN status VARCHAR(16) NOT NULL DEFAULT 'COMPLETED';
ALTER TABLE chat_turn ADD COLUMN citations_json TEXT;
ALTER TABLE chat_turn ADD COLUMN tool_calls_json TEXT;
ALTER TABLE chat_turn ADD COLUMN reasoning_steps_json TEXT;
ALTER TABLE chat_turn ADD COLUMN model_code VARCHAR(64);
ALTER TABLE chat_turn ADD COLUMN error_message TEXT;
ALTER TABLE chat_turn ADD COLUMN completed_at TIMESTAMPTZ;
UPDATE chat_turn SET message_code = CONCAT('legacy-', id) WHERE message_code IS NULL;
ALTER TABLE chat_turn ALTER COLUMN message_code SET NOT NULL;

CREATE UNIQUE INDEX uk_chat_turn_message_code ON chat_turn(message_code);
CREATE UNIQUE INDEX uk_chat_turn_user_session_client_message
    ON chat_turn(user_id, session_code, client_message_id)
    WHERE client_message_id IS NOT NULL;
CREATE INDEX idx_chat_turn_user_session_created ON chat_turn(user_id, session_code, created_at);

ALTER TABLE agent_profile_version
    ADD COLUMN IF NOT EXISTS routing_model VARCHAR(64);

UPDATE agent_profile_version
SET routing_model = COALESCE(NULLIF(TRIM(chat_model), ''), 'qwen-plus')
WHERE routing_model IS NULL OR TRIM(routing_model) = '';

ALTER TABLE agent_profile_version
    ALTER COLUMN routing_model SET NOT NULL;

ALTER TABLE agent_profile_version
    ALTER COLUMN routing_model SET DEFAULT 'qwen-plus';

ALTER TABLE knowledge_document ADD COLUMN IF NOT EXISTS uploader_type VARCHAR(32) NOT NULL DEFAULT 'ADMIN', ADD COLUMN IF NOT EXISTS uploader_user_id BIGINT, ADD COLUMN IF NOT EXISTS visibility_type VARCHAR(16) NOT NULL DEFAULT 'PUBLIC', ADD COLUMN IF NOT EXISTS extension_json TEXT NOT NULL DEFAULT '{}', ADD COLUMN IF NOT EXISTS source_markdown TEXT NOT NULL DEFAULT '', ADD COLUMN IF NOT EXISTS vector_config_json TEXT NOT NULL DEFAULT '{}', ADD COLUMN IF NOT EXISTS category_id BIGINT;
ALTER TABLE document_asset ADD COLUMN IF NOT EXISTS provider VARCHAR(32) NOT NULL DEFAULT 'local', ADD COLUMN IF NOT EXISTS object_key VARCHAR(512), ADD COLUMN IF NOT EXISTS content_length BIGINT;
CREATE TABLE IF NOT EXISTS admin_operator ( id BIGSERIAL PRIMARY KEY, username VARCHAR(128) NOT NULL UNIQUE, password_hash VARCHAR(255), created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE IF NOT EXISTS document_category ( id BIGSERIAL PRIMARY KEY, name VARCHAR(128) NOT NULL UNIQUE, source VARCHAR(32) NOT NULL DEFAULT 'SYSTEM', created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE IF NOT EXISTS document_tag ( id BIGSERIAL PRIMARY KEY, name VARCHAR(128) NOT NULL UNIQUE, source VARCHAR(32) NOT NULL DEFAULT 'SYSTEM', created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE IF NOT EXISTS document_tag_binding ( id BIGSERIAL PRIMARY KEY, document_id BIGINT NOT NULL REFERENCES knowledge_document(id) ON DELETE CASCADE, tag_id BIGINT NOT NULL REFERENCES document_tag(id) ON DELETE CASCADE, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP ); CREATE UNIQUE INDEX IF NOT EXISTS uk_document_tag_binding_doc_tag ON document_tag_binding(document_id, tag_id);
CREATE TABLE IF NOT EXISTS document_review_request ( id BIGSERIAL PRIMARY KEY, request_code VARCHAR(64) NOT NULL UNIQUE, source_document_id BIGINT REFERENCES knowledge_document(id), title VARCHAR(128) NOT NULL, source_filename VARCHAR(256) NOT NULL, uploader_type VARCHAR(32) NOT NULL DEFAULT 'ADMIN', uploader_user_id BIGINT, visibility_type VARCHAR(16) NOT NULL DEFAULT 'PUBLIC', status VARCHAR(24) NOT NULL, stage VARCHAR(64) NOT NULL DEFAULT 'CREATED', progress_percent INTEGER NOT NULL DEFAULT 0, source_markdown TEXT NOT NULL DEFAULT '', normalized_markdown_path VARCHAR(512), extension_json TEXT NOT NULL DEFAULT '{}', vector_config_json TEXT NOT NULL DEFAULT '{}', suggested_category_name VARCHAR(128), suggested_tags_json TEXT NOT NULL DEFAULT '[]', selected_category_name VARCHAR(128), selected_tags_json TEXT NOT NULL DEFAULT '[]', taxonomy_reasoning TEXT, review_reason TEXT, reviewed_by_user_id BIGINT, reviewed_at TIMESTAMPTZ, error_message TEXT, published_document_id BIGINT REFERENCES knowledge_document(id), created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE IF NOT EXISTS document_review_asset ( id BIGSERIAL PRIMARY KEY, review_request_id BIGINT NOT NULL REFERENCES document_review_request(id) ON DELETE CASCADE, original_path VARCHAR(512) NOT NULL, stored_url VARCHAR(512) NOT NULL, provider VARCHAR(32) NOT NULL DEFAULT 'local', object_key VARCHAR(512), content_type VARCHAR(128), content_length BIGINT, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE IF NOT EXISTS document_review_chunk ( id BIGSERIAL PRIMARY KEY, review_request_id BIGINT NOT NULL REFERENCES document_review_request(id) ON DELETE CASCADE, chunk_index INTEGER NOT NULL, heading_path VARCHAR(512) NOT NULL, anchor VARCHAR(128) NOT NULL, content TEXT NOT NULL, metadata_json TEXT NOT NULL DEFAULT '{}', created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE IF NOT EXISTS document_index_rebuild_job ( id BIGSERIAL PRIMARY KEY, job_code VARCHAR(64) NOT NULL UNIQUE, status VARCHAR(24) NOT NULL, triggered_by_user_id BIGINT, source_vector_table VARCHAR(128) NOT NULL, target_vector_table VARCHAR(128) NOT NULL, detail_json TEXT NOT NULL DEFAULT '{}', started_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, finished_at TIMESTAMPTZ, error_message TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP ); CREATE UNIQUE INDEX IF NOT EXISTS uk_document_index_rebuild_running ON document_index_rebuild_job(status) WHERE status = 'RUNNING';
INSERT INTO admin_operator (username) SELECT 'admin' WHERE NOT EXISTS (SELECT 1 FROM admin_operator WHERE username = 'admin');
INSERT INTO document_category (name, source) SELECT '项目定义', 'SYSTEM' WHERE NOT EXISTS (SELECT 1 FROM document_category WHERE name = '项目定义');
INSERT INTO document_category (name, source) SELECT 'Agent定义', 'SYSTEM' WHERE NOT EXISTS (SELECT 1 FROM document_category WHERE name = 'Agent定义');
INSERT INTO document_tag (name, source) SELECT 'knowledge-box', 'SYSTEM' WHERE NOT EXISTS (SELECT 1 FROM document_tag WHERE name = 'knowledge-box');
INSERT INTO document_tag (name, source) SELECT 'agent', 'SYSTEM' WHERE NOT EXISTS (SELECT 1 FROM document_tag WHERE name = 'agent');
UPDATE knowledge_document SET title = 'Knowledge Box 项目定义', source_filename = 'knowledge-box-project-definition.md', visibility_type = 'PUBLIC', uploader_type = 'ADMIN', uploader_user_id = (SELECT id FROM admin_operator WHERE username = 'admin'), source_markdown = E'# Knowledge Box 项目定义\n\nKnowledge Box 是一个面向知识库问答和管理闭环的工程项目。\n', extension_json = '{}', vector_config_json = '{"embeddingModel":"text-embedding-v3","chunkSize":900}', tags = '["knowledge-box"]' WHERE id = 1;
UPDATE knowledge_document SET title = 'Knowledge Box Agent 定义', source_filename = 'knowledge-box-agent-definition.md', visibility_type = 'AGENT_ONLY', uploader_type = 'ADMIN', uploader_user_id = (SELECT id FROM admin_operator WHERE username = 'admin'), source_markdown = E'# Knowledge Box Agent 定义\n\n系统默认使用 ReActAgent 执行问答编排。\n', extension_json = '{}', vector_config_json = '{"embeddingModel":"text-embedding-v3","chunkSize":900}', tags = '["agent"]' WHERE id = 2;

SELECT setval('admin_operator_id_seq', COALESCE((SELECT MAX(id) FROM admin_operator), 1), true);
SELECT setval('document_category_id_seq', COALESCE((SELECT MAX(id) FROM document_category), 1), true);
SELECT setval('document_tag_id_seq', COALESCE((SELECT MAX(id) FROM document_tag), 1), true);
SELECT setval('document_tag_binding_id_seq', COALESCE((SELECT MAX(id) FROM document_tag_binding), 1), true);
SELECT setval('document_review_request_id_seq', COALESCE((SELECT MAX(id) FROM document_review_request), 1), true);
SELECT setval('document_review_asset_id_seq', COALESCE((SELECT MAX(id) FROM document_review_asset), 1), true);
SELECT setval('document_review_chunk_id_seq', COALESCE((SELECT MAX(id) FROM document_review_chunk), 1), true);
SELECT setval('document_index_rebuild_job_id_seq', COALESCE((SELECT MAX(id) FROM document_index_rebuild_job), 1), true);

ALTER TABLE tool_definition ADD COLUMN IF NOT EXISTS class_name VARCHAR(255), ADD COLUMN IF NOT EXISTS bean_name VARCHAR(255), ADD COLUMN IF NOT EXISTS config_json TEXT;
UPDATE tool_definition SET class_name = COALESCE(NULLIF(class_name, ''), 'com.knowledgebox.service.chat.KnowledgeBaseSearchTool'), bean_name = COALESCE(NULLIF(bean_name, ''), 'knowledgeBaseSearchTool'), config_json = COALESCE(config_json, '{}') WHERE code = 'http-search';
ALTER TABLE mcp_server ADD COLUMN IF NOT EXISTS headers_encrypted_json TEXT NOT NULL DEFAULT '{}', ADD COLUMN IF NOT EXISTS query_params_json TEXT NOT NULL DEFAULT '{}', ADD COLUMN IF NOT EXISTS timeout_ms BIGINT, ADD COLUMN IF NOT EXISTS initialization_timeout_ms BIGINT;
ALTER TABLE skill_binding ADD COLUMN IF NOT EXISTS description VARCHAR(1000), ADD COLUMN IF NOT EXISTS source_type VARCHAR(32) NOT NULL DEFAULT 'UPLOAD', ADD COLUMN IF NOT EXISTS oss_object_key VARCHAR(512), ADD COLUMN IF NOT EXISTS checksum_md5 VARCHAR(64);
UPDATE skill_binding SET description = COALESCE(description, NULLIF(prompt_template, '')) WHERE description IS NULL;
CREATE TABLE IF NOT EXISTS agent_profile_version_tool_binding ( id BIGSERIAL PRIMARY KEY, profile_version_id BIGINT NOT NULL REFERENCES agent_profile_version(id) ON DELETE CASCADE, tool_id BIGINT NOT NULL REFERENCES tool_definition(id) ON DELETE CASCADE, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE UNIQUE INDEX IF NOT EXISTS uk_profile_tool_binding ON agent_profile_version_tool_binding(profile_version_id, tool_id); CREATE INDEX IF NOT EXISTS idx_profile_tool_binding_tool_id ON agent_profile_version_tool_binding(tool_id);
CREATE TABLE IF NOT EXISTS agent_profile_version_mcp_binding ( id BIGSERIAL PRIMARY KEY, profile_version_id BIGINT NOT NULL REFERENCES agent_profile_version(id) ON DELETE CASCADE, mcp_id BIGINT NOT NULL REFERENCES mcp_server(id) ON DELETE CASCADE, enable_tools_json TEXT NOT NULL DEFAULT '[]', disable_tools_json TEXT NOT NULL DEFAULT '[]', created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE UNIQUE INDEX IF NOT EXISTS uk_profile_mcp_binding ON agent_profile_version_mcp_binding(profile_version_id, mcp_id); CREATE INDEX IF NOT EXISTS idx_profile_mcp_binding_mcp_id ON agent_profile_version_mcp_binding(mcp_id);
CREATE TABLE IF NOT EXISTS agent_profile_version_skill_binding ( id BIGSERIAL PRIMARY KEY, profile_version_id BIGINT NOT NULL REFERENCES agent_profile_version(id) ON DELETE CASCADE, skill_id BIGINT NOT NULL REFERENCES skill_binding(id) ON DELETE CASCADE, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE UNIQUE INDEX IF NOT EXISTS uk_profile_skill_binding ON agent_profile_version_skill_binding(profile_version_id, skill_id); CREATE INDEX IF NOT EXISTS idx_profile_skill_binding_skill_id ON agent_profile_version_skill_binding(skill_id);
INSERT INTO agent_profile_version_tool_binding (profile_version_id, tool_id) SELECT version.id, definition.id FROM agent_profile_version version, LATERAL jsonb_array_elements_text( COALESCE(NULLIF(version.tool_bindings, ''), '[]')::jsonb ) AS tool_code(value) JOIN tool_definition definition ON definition.code = tool_code.value ON CONFLICT (profile_version_id, tool_id) DO NOTHING;
INSERT INTO agent_profile_version_mcp_binding (profile_version_id, mcp_id, enable_tools_json, disable_tools_json) SELECT version.id, server.id, '[]', '[]' FROM agent_profile_version version, LATERAL jsonb_array_elements_text( COALESCE(NULLIF(version.mcp_bindings, ''), '[]')::jsonb ) AS mcp_code(value) JOIN mcp_server server ON server.code = mcp_code.value ON CONFLICT (profile_version_id, mcp_id) DO NOTHING;
INSERT INTO agent_profile_version_skill_binding (profile_version_id, skill_id) SELECT version.id, skill.id FROM agent_profile_version version, LATERAL jsonb_array_elements_text( COALESCE(NULLIF(version.skill_bindings, ''), '[]')::jsonb ) AS skill_code(value) JOIN skill_binding skill ON skill.code = skill_code.value ON CONFLICT (profile_version_id, skill_id) DO NOTHING;
